// Using Vertex AI Node.js client
const {AgentClient} = require('@google-cloud/aiplatform');

const client = new AgentClient({
  projectId: 'your-project-id',
  location: 'us-central1'
});

const response = await client.invoke('data-analyst-agent', {
  request: 'Analyze gross margin by region',
  dataset_name: 'trade_data'
});

console.log(response.outputs.executive_brief_pdf);
